export function IcoSnapToRoads() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Road line */}
      <line x1="20" y1="72" x2="180" y2="72" stroke={palette.mid} strokeWidth="5" strokeLinecap="round" opacity="0.6" />
      {/* Scattered dots */}
      {[
        [38, 52], [60, 88], [80, 48], [105, 92], [128, 55], [152, 85],
      ].map(([x, y]) => (
        <g key={`${x}-${y}`}>
          <circle cx={x} cy={y} r="5" fill={palette.soft} opacity="0.5" />
          {/* Snap line to road */}
          <line x1={x} y1={y} x2={x} y2="72" stroke={palette.accent} strokeWidth="1.5" strokeDasharray="3 2" opacity="0.6" />
          <circle cx={x} cy="72" r="4" fill={palette.accent} />
        </g>
      ))}
    </svg>
  );
}
